mapper.update:
update stage_template
set template_name = #{templateName},
    business_type = #{businessType},
    remark = #{remark},
    status = #{status}
where id = #{id}

update product_category
set category_name = #{categoryName},
    status = #{status}
where id = #{id}

update notice_info
set title = #{title},
    content = #{content},
    publish_status = #{publishStatus}
where id = #{id}
